"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[5790],{5516(e){e.exports=JSON.parse('{"tag":{"label":"persona:software-engineer","permalink":"/tags/persona-software-engineer","allTagsPath":"/tags","count":10,"items":[{"id":"catalog/development/data-handling/cache-static-data","title":"Cache static data","description":"From an energy-efficiency perspective, it\'s better to reduce network traffic by reading the data locally through a cache rather than accessing it remotely over the network. Shortening the distance a network packet travels means that less energy is required to transmit it. Similarly, from an embodied carbon perspective, we are more efficient with hardware when a network packet traverses through less computing equipment.","permalink":"/catalog/development/data-handling/cache-static-data"},{"id":"catalog/operations/resource-lifecycle/delete-unused-storage-resources","title":"Delete unused storage resources","description":"From an embodied carbon perspective, it\'s better to delete unused storage resources so we are efficient with hardware and so that the storage layer is optimised for the task.","permalink":"/catalog/operations/resource-lifecycle/delete-unused-storage-resources"},{"id":"catalog/requirements/match-slo","title":"Match your service level objectives to business needs","description":"If service downtimes are acceptable it\'s better to not strive for highest availability but to design the solution according to real business needs. Lower availability guarantees can help reduce energy consumption by using less infrastructure components.","permalink":"/catalog/requirements/match-slo"},{"id":"catalog/requirements/optimize-impact-on-customer-equipment","title":"Optimize impact on customer devices and equipment","description":"Description","permalink":"/catalog/requirements/optimize-impact-on-customer-equipment"},{"id":"catalog/development/data-handling/reduce-transmitted-data","title":"Reduce transmitted data","description":"From an energy-efficiency perspective, it\'s better to minimize the size of the data transmitted so that less energy is required because the network traffic is reduced.","permalink":"/catalog/development/data-handling/reduce-transmitted-data"},{"id":"catalog/operations/resource-lifecycle/remove-unused-assets","title":"Remove unused assets","description":"Description","permalink":"/catalog/operations/resource-lifecycle/remove-unused-assets"},{"id":"catalog/architecture/technology-selection/energy-efficent-framework","title":"Select a more energy efficient AI/ML framework","description":"Training an AI model implies a significant carbon footprint. The underlying framework used for the development, training, and deployment of AI/ML needs to be evaluated and considered to ensure the process is as energy efficient as possible.","permalink":"/catalog/architecture/technology-selection/energy-efficent-framework"},{"id":"catalog/development/use-async-instead-of-sync","title":"Use Asynchronous network calls instead of synchronous","description":"When making calls across process boundaries to either databases or file systems or REST APIs, relying on synchronous calls can cause the calling thread to become blocked, putting additional load on the CPU","permalink":"/catalog/development/use-async-instead-of-sync"},{"id":"catalog/operations/capacity-management/use-circuit-breaker","title":"Use circuit breaker patterns","description":"Modern applications need to communicate with other applications on a regular basis. Since these other applications have their own deployment schedule, downtimes and availability, the network connection to these application might have problems. If the other application is not reachable, all network requests against this other application will fail and future network requests are futile.","permalink":"/catalog/operations/capacity-management/use-circuit-breaker"},{"id":"catalog/development/media-and-code-efficiency/use-compiled-languages","title":"Use compiled languages","description":"Description","permalink":"/catalog/development/media-and-code-efficiency/use-compiled-languages"}],"unlisted":false}}')}}]);